    """Return node containing key or None"""
    current = self.head
    while current:
        if current.data == key:
            return current
        current = current.next
    return None

def search_position(self, key):
    """Return position of key or -1 if not found"""
    current = self.head
    position = 0
    while current:
        if current.data == key:
            return position
        position += 1
        current = current.next
    return -1

def __contains__(self, key):
    """Enable 'in' operator"""
    return self.search(key) is not None

